import { NextRequest, NextResponse } from "next/server";
import { initializeDB } from "@/lib/db";
import { handleStripeWebhook } from "@/lib/stripe";

await initializeDB();

export async function POST(request: NextRequest) {
  try {
    const body = await request.text();
    const signature = request.headers.get("stripe-signature") || "";

    const result = await handleStripeWebhook(body, signature);

    if (!result.handled) {
      return NextResponse.json({ error: "Webhook handling failed" }, { status: 400 });
    }

    return NextResponse.json({ received: true, event: result.event });
  } catch (err) {
    console.error("Stripe webhook error:", err);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { initializeDB, createFormSubmission, getFormById } from "@/lib/db";
import { createLead } from "@/lib/db";

await initializeDB();

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { formId, data } = body;

    if (!formId || !data) {
      return NextResponse.json({ error: "formId and data are required" }, { status: 400 });
    }

    const form = getFormById(formId);
    if (!form) {
      return NextResponse.json({ error: "Form not found" }, { status: 404 });
    }

    const submission = createFormSubmission({ formId, data });

    // Also create a lead
    const nameField = form.fields.find((f) => f.type === "text" || f.type === "textarea");
    const emailField = form.fields.find((f) => f.type === "email");
    const phoneField = form.fields.find((f) => f.type === "phone");

    createLead({
      campaignId: null,
      source: `form:${form.name}`,
      status: "new",
      name: nameField ? data[nameField.label] || "Unknown" : "Unknown",
      email: emailField ? data[emailField.label] || "" : "",
      phone: phoneField ? data[phoneField.label] || "" : "",
      notes: `Submitted via form: ${form.name}`,
      capturedAt: new Date().toISOString(),
    });

    return NextResponse.json({ data: submission, message: "Submission recorded" }, { status: 201 });
  } catch (err) {
    console.error("Form submission error:", err);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { initializeDB, createBooking, getPackageById, getBookings } from "@/lib/db";
import { auth } from "@/lib/auth";
import { bookingConfirmation, sendEmail } from "@/lib/email";
import { trackBooking } from "@/lib/analytics";

await initializeDB();

export async function POST(request: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await request.json();
    const { slotStart, packageId, notes } = body;

    if (!slotStart || !packageId) {
      return NextResponse.json({ error: "slotStart and packageId are required" }, { status: 400 });
    }

    const pkg = getPackageById(packageId);
    const slotDate = new Date(slotStart);
    const slotEnd = new Date(slotDate.getTime() + 30 * 60 * 1000);

    const booking = createBooking({
      userId: session.user.id,
      customerId: null,
      packageId,
      slotStart: slotDate.toISOString(),
      slotEnd: slotEnd.toISOString(),
      status: "scheduled",
      metadata: notes || "",
    });

    // Send confirmation email
    const emailData = bookingConfirmation(
      session.user.name || "User",
      slotDate.toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric" }),
      slotDate.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" }),
      pkg?.name || packageId
    );
    emailData.to = session.user.email || "";
    await sendEmail(emailData);

    trackBooking(session.user.id, packageId);

    return NextResponse.json({ data: booking, message: "Booking created" }, { status: 201 });
  } catch (err) {
    console.error("Booking API error:", err);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

