import NextAuth from "next-auth";
import Credentials from "next-auth/providers/credentials";

const handler = NextAuth({
  providers: [
    Credentials({
      credentials: {
        email: { label: "Email", type: "email" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        if (!credentials?.email || !credentials?.password) return null;
        // For demo, accept demo@demo.app / demo123
        if (credentials.email === "demo@demo.app" && credentials.password === "demo123") {
          return { id: "demo-user", email: "demo@demo.app", name: "Demo User", role: "customer" };
        }
        if (credentials.email === "admin@goon.app" && credentials.password === "admin123") {
          return { id: "admin-user", email: "admin@goon.app", name: "Admin User", role: "admin" };
        }
        return null;
      },
    }),
  ],
  session: { strategy: "jwt" },
  pages: { signIn: "/auth/login" },
  callbacks: {
    async jwt({ token, user }) {
      if (user) { token.role = (user as Record<string, unknown>).role; }
      return token;
    },
    async session({ session, token }) {
      if (session.user) { (session.user as Record<string, unknown>).role = token.role; }
      return session;
    },
  },
});

export { handler as GET, handler as POST };

